"use client";

import { useState, useTransition } from "react";
import { useRouter, Link } from "@/i18n/navigation";
import type { AppRole } from "@/lib/auth";
import { useTranslations } from "next-intl";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { toast } from "@/components/ui/toast";
import { Loader2 } from "lucide-react";
import {
  assignTranslatorAction,
  setTranslationStatusAction,
} from "../../actions";

type Translation = {
  locale: string;
  status: "PENDING" | "IN_PROGRESS" | "REVIEW" | "PUBLISHED";
  slug: string;
  translator: { id: string; name: string | null; email: string } | null;
  basedOnSourceVersion: number;
};

export function TranslatorAssignmentPanel({
  articleId,
  sourceLocale,
  sourceVersion,
  targetLocales,
  translations,
  ctvs,
}: {
  articleId: string;
  sourceLocale: string;
  sourceVersion: number;
  targetLocales: string[];
  translations: Translation[];
  ctvs: Array<{
    id: string;
    name: string | null;
    email: string;
    role: AppRole;
  }>;
}) {
  const router = useRouter();
  const t = useTranslations("admin.articles.translatorPanel");
  const [pending, startTransition] = useTransition();

  return (
    <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 xl:grid-cols-3">
      {targetLocales.map((locale) => {
        const tr = translations.find((tr) => tr.locale === locale);
        return (
          <TranslationRow
            key={locale}
            articleId={articleId}
            sourceVersion={sourceVersion}
            locale={locale}
            tr={tr}
            ctvs={ctvs}
            pending={pending}
            onAssign={(translatorId) =>
              startTransition(async () => {
                const res = await assignTranslatorAction({
                  articleId,
                  locale,
                  translatorId,
                });
                if (!res.ok) {
                  toast.error(res.error);
                  return;
                }
                toast.success(
                  t("assignmentUpdated", { locale: locale.toUpperCase() }),
                );
                router.refresh();
              })
            }
            onPublish={() =>
              startTransition(async () => {
                const res = await setTranslationStatusAction({
                  articleId,
                  locale,
                  status: "PUBLISHED",
                });
                if (!res.ok) {
                  toast.error(res.error);
                  return;
                }
                toast.success(
                  t("translationPublished", { locale: locale.toUpperCase() }),
                );
                router.refresh();
              })
            }
          />
        );
      })}
      {targetLocales.length === 0 && (
        <p className="text-sm text-[hsl(var(--muted-foreground))] sm:col-span-2 xl:col-span-3">
          {t("noTargets")}
        </p>
      )}
    </div>
  );
}

function localeLabel(code: string): string {
  try {
    return (
      new Intl.DisplayNames(["en"], { type: "language" }).of(code) ?? code
    );
  } catch {
    return code;
  }
}

function TranslationRow({
  articleId,
  sourceVersion,
  locale,
  tr,
  ctvs,
  pending,
  onAssign,
  onPublish,
}: {
  articleId: string;
  sourceVersion: number;
  locale: string;
  tr?: Translation;
  ctvs: Array<{
    id: string;
    name: string | null;
    email: string;
    role: AppRole;
  }>;
  pending: boolean;
  onAssign: (translatorId: string | null) => void;
  onPublish: () => void;
}) {
  const tPanel = useTranslations("admin.articles.translatorPanel");
  const tTrans = useTranslations("admin.translations");
  const [selected, setSelected] = useState(tr?.translator?.id ?? "");
  const isStale =
    tr && tr.basedOnSourceVersion < sourceVersion && tr.status === "PUBLISHED";

  return (
    <div className="flex flex-col gap-3 rounded-xl border border-[hsl(var(--border))] bg-[hsl(var(--inset))] p-4">
      <div className="flex items-start justify-between gap-2">
        <div className="flex items-center gap-2">
          <span className="inline-flex h-7 min-w-7 items-center justify-center rounded-md bg-[hsl(var(--hover))] px-1.5 font-mono text-xs font-semibold uppercase tracking-[0.6px] text-[hsl(var(--foreground))]">
            {locale}
          </span>
          <span className="text-sm font-medium text-[hsl(var(--foreground))]">
            {localeLabel(locale)}
          </span>
        </div>
        <div className="flex flex-wrap items-center justify-end gap-1.5">
          {tr ? (
            <Badge
              tone={
                tr.status === "PUBLISHED"
                  ? "published"
                  : tr.status === "REVIEW"
                    ? "review"
                    : tr.status === "IN_PROGRESS"
                      ? "in_progress"
                      : "pending"
              }
            >
              {tr.status}
            </Badge>
          ) : (
            <Badge tone="pending">{tPanel("unassigned")}</Badge>
          )}
          {isStale && <Badge tone="review">{tTrans("stale")}</Badge>}
        </div>
      </div>

      <div className="flex items-center gap-2">
        <Select
          value={selected}
          onValueChange={(v) => {
            setSelected(v);
            onAssign(v === "__none__" ? null : v);
          }}
        >
          <SelectTrigger className="w-full">
            <SelectValue placeholder={tPanel("assignPlaceholder")} />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="__none__">{tPanel("unassigned")}</SelectItem>
            {ctvs.map((c) => (
              <SelectItem key={c.id} value={c.id}>
                {c.name ?? c.email}{" "}
                <span className="ml-1 text-xs text-[hsl(var(--muted-foreground))]">
                  ({c.role})
                </span>
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
        {pending && (
          <Loader2
            size={14}
            className="shrink-0 animate-spin text-[hsl(var(--muted-foreground))]"
          />
        )}
      </div>

      <div className="flex items-center justify-between gap-2 border-t border-[hsl(var(--border))] pt-2">
        {tr ? (
          <Button asChild size="sm" variant="ghost" className="px-2">
            <Link href={`/admin/articles/${articleId}/translate/${locale}`}>
              {tPanel("openTranslation")}
            </Link>
          </Button>
        ) : (
          <span className="text-xs text-[hsl(var(--muted-foreground))]">
            {tPanel("assignPlaceholder")}
          </span>
        )}
        {tr && tr.status === "REVIEW" && (
          <Button size="sm" onClick={onPublish} disabled={pending}>
            {tPanel("publish")}
          </Button>
        )}
      </div>
    </div>
  );
}
